console.assert(e.code === 'MY_CODE', 'code');
console.assert(e.message === 'human text', 'message');
console.assert(e instanceof Error, 'instanceof Error');
console.assert(e instanceof AppError, 'instanceof AppError');

// success paths unchanged
console.assert(divide(10, 2) === 5, 'divide');
console.assert(checkToken('tk_abc123') === true, 'checkToken');
console.assert(validateName('  alice  ') === 'alice', 'validateName');

// throw paths produce AppError
try { divide(1, 0); } catch(err) {
  console.assert(err instanceof AppError, 'DIV_ZERO type');
  console.assert(err.code === 'DIV_ZERO', 'DIV_ZERO code');
  console.assert(err.message === 'division by zero', 'DIV_ZERO message');
}

try { checkToken('bad'); } catch(err) {
  console.assert(err.code === 'BAD_TOKEN', 'BAD_TOKEN code');
  console.assert(err.message === 'token malformed', 'BAD_TOKEN message');
}

